// Java 26 - Primitive type patterns (PREVIEW, --enable-preview)
// Learn: match primitive types directly in a switch.
String classify(Object value) {
    return switch (value) {
        // Primitive patterns bind the matched value.
        case int i -> "int " + i;
        case long l -> "long " + l;
        case double d -> "double " + d;
        default -> "other";
    };
}
